"""Modelo global para el experimento de aprendizaje federado.Este módulo define una clase que encapsula:- el escalado de variables,- la codificación de etiquetas,- el clasificador base,- la evaluación,- la actualización local de clientes,- y la serialización del modelo."""from __future__ import annotationsimport copyfrom pathlib import Pathfrom typing import Any, Dict, Sequenceimport joblibimport numpy as npfrom sklearn.linear_model import SGDClassifier# Opciones posibles para el futuro:# from sklearn.linear_model import Perceptron# from sklearn.linear_model import PassiveAggressiveClassifierfrom sklearn.metrics import (    accuracy_score,    balanced_accuracy_score,    classification_report,    confusion_matrix,    f1_score,)from sklearn.preprocessing import LabelEncoder, StandardScalerclass FederatedGlobalModel:    """    Modelo global del sistema federado.    Parameters    ----------    random_state : int        Semilla aleatoria para reproducibilidad.    """    def __init__(self, random_state: int = 42) -> None:        self.random_state = random_state        self.scaler = StandardScaler()        self.label_encoder = LabelEncoder()        # Modelo base actual:        # SGDClassifier es una buena opción inicial porque soporta partial_fit        # y funciona bien en aprendizaje incremental.        self.model = SGDClassifier(            loss="log_loss",            penalty="l2",            alpha=1e-4,            max_iter=1,            learning_rate="optimal",            tol=None,            random_state=random_state,            warm_start=True,        )        self.is_fitted = False    def fit_initial(self, X: np.ndarray, y_str: Sequence[str]) -> None:        """        Entrena el modelo global inicial usando el conjunto seed.        Parameters        ----------        X : np.ndarray            Matriz de características.        y_str : Sequence[str]            Etiquetas de clase en formato texto.        """        y = self.label_encoder.fit_transform(np.asarray(y_str))        X_scaled = self.scaler.fit_transform(X).astype(np.float64, copy=False)        classes = np.arange(len(self.label_encoder.classes_))        self.model.partial_fit(X_scaled, y, classes=classes)        for _ in range(20):            self.model.partial_fit(X_scaled, y)        self.is_fitted = True    def predict(self, X: np.ndarray) -> np.ndarray:        """        Predice las clases en formato texto.        Parameters        ----------        X : np.ndarray            Matriz de características.        Returns        -------        np.ndarray            Predicciones en las etiquetas originales.        """        self._check_fitted()        X_scaled = self.scaler.transform(X).astype(np.float64, copy=False)        y_pred = self.model.predict(X_scaled)        return self.label_encoder.inverse_transform(y_pred)    def evaluate(self, X: np.ndarray, y_str: Sequence[str]) -> Dict[str, float]:        """        Evalúa el modelo sobre un conjunto de datos.        Parameters        ----------        X : np.ndarray            Matriz de características.        y_str : Sequence[str]            Etiquetas reales en formato texto.        Returns        -------        Dict[str, float]            Diccionario con accuracy, balanced_accuracy y macro_f1.        """        self._check_fitted()        y_true = self.label_encoder.transform(np.asarray(y_str))        X_scaled = self.scaler.transform(X).astype(np.float64, copy=False)        y_pred = self.model.predict(X_scaled)        return {            "accuracy": float(accuracy_score(y_true, y_pred)),            "balanced_accuracy": float(balanced_accuracy_score(y_true, y_pred)),            "macro_f1": float(f1_score(y_true, y_pred, average="macro", zero_division=0)),        }    def classification_details(self, X: np.ndarray, y_str: Sequence[str]) -> Dict[str, Any]:        """        Devuelve información detallada de clasificación.        Parameters        ----------        X : np.ndarray            Matriz de características.        y_str : Sequence[str]            Etiquetas reales en formato texto.        Returns        -------        Dict[str, Any]            Diccionario con:            - labels            - classification_report            - confusion_matrix            - y_true            - y_pred        """        self._check_fitted()        y_true_str = np.asarray(y_str)        y_pred_str = self.predict(X)        labels = list(self.label_encoder.classes_)        report_dict = classification_report(            y_true_str,            y_pred_str,            labels=labels,            output_dict=True,            zero_division=0,        )        cm = confusion_matrix(y_true_str, y_pred_str, labels=labels)        return {            "labels": labels,            "classification_report": report_dict,            "confusion_matrix": cm,            "y_true": y_true_str,            "y_pred": y_pred_str,        }    def client_update(        self,        X_client: np.ndarray,        y_client_str: Sequence[str],        local_epochs: int = 1,        noise_std: float = 0.0,    ) -> Dict[str, Any]:        """        Simula la actualización local de un cliente móvil.        Parameters        ----------        X_client : np.ndarray            Datos locales del cliente.        y_client_str : Sequence[str]            Etiquetas locales del cliente.        local_epochs : int            Número de épocas locales.        noise_std : float            Desviación típica del ruido gaussiano añadido al final.        Returns        -------        Dict[str, Any]            Diccionario con:            - coef_            - intercept_            - n_samples        """        self._check_fitted()        y_client = self.label_encoder.transform(np.asarray(y_client_str))        X_scaled = self.scaler.transform(X_client).astype(np.float64, copy=False)        local_model = copy.deepcopy(self.model)        indices = np.arange(len(X_scaled))        for _ in range(local_epochs):            np.random.shuffle(indices)            X_epoch = X_scaled[indices]            y_epoch = y_client[indices]            local_model.partial_fit(X_epoch, y_epoch)        coef = local_model.coef_.copy().astype(np.float64, copy=False)        intercept = local_model.intercept_.copy().astype(np.float64, copy=False)        if noise_std > 0.0:            coef += np.random.normal(0.0, noise_std, size=coef.shape)            intercept += np.random.normal(0.0, noise_std, size=intercept.shape)        return {            "coef_": coef,            "intercept_": intercept,            "n_samples": len(X_client),        }    def get_state(self) -> Dict[str, Any]:        """        Devuelve el estado necesario para reconstruir el modelo.        Returns        -------        Dict[str, Any]            Estado serializable del modelo.        """        self._check_fitted()        return {            "coef_": self.model.coef_.copy(),            "intercept_": self.model.intercept_.copy(),            "classes_": self.model.classes_.copy(),            "scaler_mean_": self.scaler.mean_.copy(),            "scaler_scale_": self.scaler.scale_.copy(),            "label_classes_": self.label_encoder.classes_.copy(),        }    def set_state(self, state: Dict[str, Any]) -> None:        """        Reconstruye el modelo a partir de un estado guardado.        Parameters        ----------        state : Dict[str, Any]            Estado previamente generado con get_state().        """        self.label_encoder.classes_ = state["label_classes_"].copy()        self.scaler.mean_ = state["scaler_mean_"].copy()        self.scaler.scale_ = state["scaler_scale_"].copy()        self.scaler.var_ = self.scaler.scale_ ** 2        self.scaler.n_features_in_ = len(self.scaler.mean_)        self.model.classes_ = state["classes_"].copy()        self.model.coef_ = state["coef_"].copy().astype(np.float64, copy=False)        self.model.intercept_ = state["intercept_"].copy().astype(np.float64, copy=False)        self.model.t_ = 1.0        self.model.n_features_in_ = state["coef_"].shape[1]        self.is_fitted = True    def save(self, path: Path) -> None:        """        Guarda el modelo en disco.        Parameters        ----------        path : Path            Ruta de salida.        """        payload = {            "state": self.get_state(),            "random_state": self.random_state,        }        joblib.dump(payload, path)    @classmethod    def load(cls, path: Path) -> "FederatedGlobalModel":        """        Carga un modelo previamente guardado.        Parameters        ----------        path : Path            Ruta del fichero guardado.        Returns        -------        FederatedGlobalModel            Modelo reconstruido.        """        payload = joblib.load(path)        model = cls(random_state=payload["random_state"])        model.set_state(payload["state"])        return model    def _check_fitted(self) -> None:        """        Comprueba que el modelo haya sido entrenado o restaurado.        """        if not self.is_fitted:            raise RuntimeError("El modelo global todavía no está entrenado.")